ee:message.ee:set-payload:
%dw 2.0 output application/json
---
{ jsonrpc: "2.0", id: null, error: { code: -32001, message: "Unauthorized" } }

%dw 2.0 output application/json
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    error: { code: -32601, message: "Method not found: " ++ vars.mcpMethod }
}

%dw 2.0 output application/json
---
{
    jsonrpc: "2.0",
    id: vars.mcpId default null,
    error: { code: -32603, message: "Internal error: " ++ (error.description default "unknown") }
}

%dw 2.0 output application/json
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    result: {
        protocolVersion: "2024-11-05",
        capabilities: { tools: {} },
        serverInfo: {
            name: "plantiq-mcp-server",
            version: "1.0.0",
            description: "PlantIQ manufacturing productivity agent — GM plant FTE optimization"
        }
    }
}

%dw 2.0 output application/json
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    result: {
        tools: [
            {
                name: "plantiq_get_gap_summary",
                description: "Returns a cross-plant FTE gap summary and total pipeline value for the current quarter. Use when asked for an overview, total gap, or pipeline across all plants.",
                inputSchema: {
                    'type': "object",
                    properties: {
                        quarter: { 'type': "string", description: "Quarter in format YYYY-QN, e.g. 2025-Q3. Defaults to current quarter if omitted." }
                    },
                    required: []
                }
            },
            {
                name: "plantiq_get_plant_status",
                description: "Returns the current status for a specific plant: FTE gap, approved FTE coverage, top pending idea, and approved ideas count. Use when asked about a specific plant.",
                inputSchema: {
                    'type': "object",
                    properties: {
                        plant_code: { 'type': "string", description: "Plant code, e.g. FLINT-1, WARREN-3, LANSING-2" }
                    },
                    required: ["plant_code"]
                }
            },
            {
                name: "plantiq_get_pending_ideas",
                description: "Returns pending-approval productivity ideas for a plant and optional shop, with FTE impact, confidence score, and benchmark evidence. Use when asked to list, review, or explain pending ideas.",
                inputSchema: {
                    'type': "object",
                    properties: {
                        plant_code: { 'type': "string", description: "Plant code, e.g. FLINT-1" },
                        shop_name:  { 'type': "string", description: "Optional shop name filter, e.g. Body Shop" },
                        quarter:    { 'type': "string", description: "Optional quarter filter, e.g. 2025-Q3" }
                    },
                    required: ["plant_code"]
                }
            },
            {
                name: "plantiq_get_benchmark_evidence",
                description: "Returns cross-plant benchmark evidence explaining why a specific idea was recommended with its confidence score. Use when asked 'why was this idea recommended' or 'what evidence supports this'.",
                inputSchema: {
                    'type': "object",
                    properties: {
                        idea_name: { 'type': "string", description: "Name of the productivity idea" },
                        shop_type: { 'type': "string", description: "Shop type for benchmark filtering, e.g. Body, Trim, Paint" }
                    },
                    required: ["idea_name"]
                }
            },
            {
                name: "plantiq_approve_idea",
                description: "Approves a PlantIQ productivity idea. Sets status to Approved in Salesforce. REQUIRES explicit user confirmation before calling. Do not call unless user has clearly said 'approve' or 'yes, approve it'.",
                inputSchema: {
                    'type': "object",
                    properties: {
                        idea_id:       { 'type': "string", description: "Salesforce ID of the GWB_Productivity_Idea__c record" },
                        approver_name: { 'type': "string", description: "Name of the person approving" }
                    },
                    required: ["idea_id", "approver_name"]
                }
            },
            {
                name: "plantiq_trigger_recommendation",
                description: "Manually triggers the PlantIQ recommendation flow for an HQ Target record, generating a new AI productivity idea. Use when asked to re-run, regenerate, or trigger a recommendation.",
                inputSchema: {
                    'type': "object",
                    properties: {
                        target_id: { 'type': "string", description: "Salesforce ID of the GWB_HQ_Target__c record" }
                    },
                    required: ["target_id"]
                }
            }
        ]
    }
}

%dw 2.0 output application/json
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    error: { code: -32602, message: "Unknown tool: " ++ vars.toolName }
}

%dw 2.0 output application/json
var pipeline = payload[0]
var gaps     = vars.plantGaps
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    result: {
        content: [{
            'type': "text",
            text: write({
                quarter:          vars.quarter,
                totalGapFTE:      (gaps reduce ((g, acc = 0.0) -> acc + (g.totalGap default 0.0))),
                totalTargetFTE:   (gaps reduce ((g, acc = 0.0) -> acc + (g.totalTarget default 0.0))),
                totalApprovedFTE: (gaps reduce ((g, acc = 0.0) -> acc + (g.totalApproved default 0.0))),
                pipelineIdeas:    pipeline.ideaCount default 0,
                pipelineFTE:      pipeline.totalFTE default 0,
                pipelineDollar:   pipeline.totalDollar default 0,
                byPlant:          gaps map {
                    plantCode:   $.`Plant__r.Plant_Code__c`,
                    plantName:   $.`Plant__r.Name`,
                    targetFTE:   $.totalTarget default 0,
                    approvedFTE: $.totalApproved default 0,
                    gapFTE:      $.totalGap default 0
                }
            }, "application/json")
        }]
    }
}

%dw 2.0 output application/json
var targets = vars.targets
var ideas   = vars.ideas
var pending = ideas filter ($.Status__c == "Pending Approval")
var approved = ideas filter ($.Status__c == "Approved")
var totalGap = (targets reduce ((t, acc = 0.0) -> acc + (t.Gap_To_Target__c default 0.0)))
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    result: {
        content: [{
            'type': "text",
            text: write({
                plantCode:          vars.plantCode,
                totalGapFTE:        totalGap,
                pendingIdeasCount:  sizeOf(pending),
                approvedIdeasCount: sizeOf(approved),
                approvedFTE:        (approved reduce ((i, acc = 0.0) -> acc + (i.FTE_Impact__c default 0.0))),
                topPendingIdea:     if (sizeOf(pending) > 0)
                                        { name: pending[0].Name, fteImpact: pending[0].FTE_Impact__c, confidence: pending[0].Confidence_Score__c }
                                    else null,
                hqTargets:          targets map {
                    quarter:     $.Quarter__c,
                    shop:        $.`Plant_Shop__r.Name`,
                    targetFTE:   $.Target_FTE__c,
                    approvedFTE: $.Approved_FTE_Coverage__c,
                    gapFTE:      $.Gap_To_Target__c
                }
            }, "application/json")
        }]
    }
}

%dw 2.0 output application/json
var ideas = payload
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    result: {
        content: [{
            'type': "text",
            text: write({
                plantCode:    vars.plantCode,
                pendingCount: sizeOf(ideas),
                ideas: ideas map {
                    id:           $.Id,
                    name:         $.Name,
                    shop:         $.`Plant_Function__r.Plant_Shop__r.Name`,
                    function:     $.`Plant_Function__r.Name`,
                    fteImpact:    $.FTE_Impact__c,
                    dollarImpact: $.Dollar_Impact__c,
                    confidence:   $.Confidence_Score__c,
                    effort:       $.Effort__c,
                    aiGenerated:  $.AI_Generated__c,
                    evidence:     $.Benchmark_Evidence__c,
                    validations:  $.Required_Validations__c,
                    reasoning:    $.Assumptions__c
                }
            }, "application/json")
        }]
    }
}

%dw 2.0 output application/json
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    error: {
        code: -32602,
        message: "Idea not found or not in Pending Approval status. ID: " ++ vars.ideaId
    }
}

%dw 2.0 output application/json
var idea = vars.ideaRecord
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    result: {
        content: [{
            'type': "text",
            text: write({
                success:      true,
                ideaId:       vars.ideaId,
                ideaName:     idea.Name,
                approvedBy:   vars.approverName,
                previousStatus: "Pending Approval",
                newStatus:    "Approved",
                fteImpact:    idea.FTE_Impact__c,
                dollarImpact: idea.Dollar_Impact__c
            }, "application/json")
        }]
    }
}

%dw 2.0 output application/json
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    error: { code: -32602, message: "HQ Target not found: " ++ vars.triggerTargetId }
}

%dw 2.0 output application/json
var t = vars.triggerTarget
---
{
    jsonrpc: "2.0",
    id: vars.mcpId,
    result: {
        content: [{
            'type': "text",
            text: write({
                triggered:  true,
                targetId:   vars.triggerTargetId,
                targetName: t.Name,
                gapFTE:     t.Gap_To_Target__c,
                message:    "Recommendation orchestration triggered via HTTP. A new PlantIQ idea will be created and posted to Slack."
            }, "application/json")
        }]
    }
}
